<?php
namespace App\Domain\Combat\Data;use App\Domain\Combat\CombatLimits;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\CombatSide;use App\Domain\Combat\CombatStateStatus;use InvalidArgumentException;
final class CombatState {private $participants;private $round;private $order;private $index;private $status;public function __construct(array $participants,$round,array $actionOrder,$currentActionIndex,$status){$map=[];$positions=[CombatSide::PLAYERS=>[],CombatSide::ENEMIES=>[]];foreach($participants as $p){if(!$p instanceof CombatParticipantState||isset($map[$p->identifier()])||isset($positions[$p->sideIdentifier()][$p->position()]))throw new InvalidArgumentException('Invalid participants.');$map[$p->identifier()]=$p;$positions[$p->sideIdentifier()][$p->position()]=true;}if(count($map)<2||empty($positions[CombatSide::PLAYERS])||empty($positions[CombatSide::ENEMIES])||count($positions[CombatSide::PLAYERS])>CombatLimits::MAX_PARTICIPANTS_PER_SIDE||count($positions[CombatSide::ENEMIES])>CombatLimits::MAX_PARTICIPANTS_PER_SIDE)throw new InvalidArgumentException('Invalid sides.');$players=$this->livingFrom($map,CombatSide::PLAYERS);$enemies=$this->livingFrom($map,CombatSide::ENEMIES);if($status===CombatStateStatus::IN_PROGRESS){if(!$players||!$enemies||$round<1||!isset($actionOrder[$currentActionIndex])||!isset($map[$actionOrder[$currentActionIndex]])||!$map[$actionOrder[$currentActionIndex]]->alive())throw new InvalidArgumentException('Invalid active state.');foreach($actionOrder as $id)if(!isset($map[$id]))throw new InvalidArgumentException('Invalid order.');}else{if($actionOrder||$currentActionIndex!==0)throw new InvalidArgumentException('Terminal state has no turn.');if($status===CombatResultStatus::CHARACTER_VICTORY&&(!$players||$enemies))throw new InvalidArgumentException('Invalid players victory.');if($status===CombatResultStatus::MONSTER_VICTORY&&(!$enemies||$players))throw new InvalidArgumentException('Invalid enemies victory.');if($status===CombatResultStatus::DRAW&&!( (!$players&&!$enemies)||($players&&$enemies)))throw new InvalidArgumentException('Invalid draw.');}$this->participants=array_values($map);$this->round=(int)$round;$this->order=array_values($actionOrder);$this->index=(int)$currentActionIndex;$this->status=$status;}private function livingFrom($map,$side){return array_values(array_filter($map,function($p)use($side){return$p->sideIdentifier()===$side&&$p->alive();}));}public function participants(){return array_slice($this->participants,0);}public function participant($id){foreach($this->participants as $p)if($p->identifier()===$id)return$p;return null;}public function participantsForSide($side){return array_values(array_filter($this->participants,function($p)use($side){return$p->sideIdentifier()===$side;}));}public function livingParticipants(){return array_values(array_filter($this->participants,function($p){return$p->alive();}));}public function livingParticipantsForSide($side){return array_values(array_filter($this->participantsForSide($side),function($p){return$p->alive();}));}public function isSideDefeated($side){return count($this->livingParticipantsForSide($side))===0;}public function isAlive($id){$p=$this->participant($id);return$p&&$p->alive();}public function roundNumber(){return$this->round;}public function actionOrder(){return array_slice($this->order,0);}public function currentActionIndex(){return$this->index;}public function nextActorIdentifier(){return$this->status===CombatStateStatus::IN_PROGRESS?$this->order[$this->index]:null;}public function status(){return$this->status;}}
